  assign out_req_o = &out_req;

  // Individually substitute bytes.
  for (genvar j = 0; j < 4; j++) begin : gen_sbox_j
    for (genvar i = 0; i < 4; i++) begin : gen_sbox_i
      aes_sbox #(
        .SBoxImpl ( SBoxImpl )
      ) u_aes_sbox_ij (
        .clk_i         ( clk_i               ),
        .rst_ni        ( rst_ni              ),
        .en_i          ( en_i                ),
        .out_req_o     ( out_req[i][j]       ),
        .out_ack_i     ( out_ack_i           ),
        .op_i          ( op_i                ),
        .data_i        ( data_i[i][j]        ),
